#### After: Redis 캐시 적용

```kotlin
// MatchingService.kt
private val objectMapper: ObjectMapper,
private val redisTemplate: StringRedisTemplate,

@Transactional(readOnly = true)
fun getWaitingPool(): List<WaitingWithProfileDto> {
    val cacheKey = "matching:waiting-pool"
    val cached = redisTemplate.opsForValue().get(cacheKey)
    if (cached != null) {
        return objectMapper.readValue(cached) // 캐시 HIT: ~1ms
    }

    val result = waitingRepository.findWaitingWithProfiles()
    redisTemplate.opsForValue().set(
        cacheKey,
        objectMapper.writeValueAsString(result),
        Duration.ofSeconds(3) // 3초 TTL: 실시간성과 성능의 균형
    )
    return result // 캐시 MISS: ~50ms (쿼리 최적화 후)
}

// 대기 등록/취소 시 캐시 무효화
@Transactional
fun joinWaiting(userId: String) {
    waitingRepository.save(WaitingEntity(userId = userId))
    redisTemplate.delete("matching:waiting-pool") // 즉시 무효화
}
